// const const_data = []

function Sing() {
    const [{ data, loading, error }, refetch] = useAxios('http://127.0.0.1:5000/sings');

    if (loading) {
        return(
            <div className='loading'>
                <p>Загрузка данных...</p>
            </div>
        );
    }

    if (error) {
        return(
            <div className='error'>
                <p>Ошибка:</p>
                <p>{error.message}</p>
                <button onClick={() => refetch()}>
                    Повторный запрос
                </button>
            </div>
        );
    }

    return (
        <div className="users-container">
            <h1>Список пользователей</h1>

            <button onClick={() => refetch()} className="refresh-btn">
                Обновить данные
            </button>

            {data && data.length > 0 ? (
                <table className="users-table">
                <thead>
                    <tr>
                    <th>ID</th>
                    <th>Название дорожных знаков</th>
                    </tr>
                </thead>
                <tbody>
                    console.log(data.map)
                    {data.map(user => (
                    <tr key={user.id}>
                        <td>{user.id}</td>
                        <td>{user.name_sing}</td>
                    </tr>
                    ))}
                </tbody>
                </table>
            ) : (
                <p>Нет данных для отображения</p>
            )}
        </div>
    );
};

